可以使用XMLHttpRequest对象来读取JSON文件，然后使用JSON.parse()方法将其转换为JavaScript对象。接着使用for...in循环遍历对象的属性，获取每个属性对应的值并将其存储在一个数组中。以下是示例代码：

```
// 创建XMLHttpRequest对象
var xhr = new XMLHttpRequest();

// 打开JSON文件
xhr.open('GET', 'data.json', true);

// 发送请求
xhr.send();

// 监听load事件
xhr.onload = function() {
  // 如果请求成功
  if (xhr.status === 200) {
    // 将JSON字符串转换为JavaScript对象
    var obj = JSON.parse(xhr.responseText);

    // 定义一个数组来存储值
    var values = [];

    // 遍历对象的属性
    for (var key in obj) {
      // 获取每个属性对应的值并添加到数组中
      values.push(obj[key]);
    }

    // 输出数组
    console.log(values);
  } else {
    console.log('请求失败：' + xhr.status);
  }
};
```

